from dataclasses import dataclass
from datetime import datetime

@dataclass
class IncidentTimestamps:
    failure_start: datetime       # T0 — from Grafana or monitoring
    alert_fired: datetime         # T1 — from PagerDuty
    acknowledged: datetime        # T2 — from PagerDuty ack event
    mitigation_deployed: datetime # T3 — from deployment system
    resolved: datetime            # T4 — from status page

    def mttd_minutes(self) -> float:
        return (self.alert_fired - self.failure_start).total_seconds() / 60

    def mtta_minutes(self) -> float:
        return (self.acknowledged - self.alert_fired).total_seconds() / 60

    def mttm_minutes(self) -> float:
        return (self.mitigation_deployed - self.failure_start).total_seconds() / 60

    def mttr_minutes(self) -> float:
        return (self.resolved - self.failure_start).total_seconds() / 60

    def validate(self) -> list[str]:
        errors = []
        if self.alert_fired < self.failure_start:
            errors.append("Alert cannot fire before failure starts")
        if self.acknowledged < self.alert_fired:
            errors.append("Acknowledgement cannot precede alert")
        if self.mitigation_deployed < self.acknowledged:
            errors.append("Mitigation cannot precede acknowledgement")
        if self.resolved < self.mitigation_deployed:
            errors.append("Resolution cannot precede mitigation")
        return errors

def compute_aggregate_metrics(
    incidents: list[IncidentTimestamps],
    severity_filter: str | None = None,
) -> dict:
    if severity_filter:
        incidents = [i for i in incidents if i.severity == severity_filter]
    if not incidents:
        return {}
    mttd = sorted(i.mttd_minutes() for i in incidents)
    mtta = sorted(i.mtta_minutes() for i in incidents)
    mttm = sorted(i.mttm_minutes() for i in incidents)
    mttr = sorted(i.mttr_minutes() for i in incidents)

    def stats(values: list[float]) -> dict:
        n = len(values)
        return {
            "mean": round(sum(values) / n, 1),
            "p50": round(values[n // 2], 1),
            "p90": round(values[int(n * 0.9)], 1),
            "max": round(values[-1], 1),
        }

    return {
        "sample_size": len(incidents),
        "mttd": stats(mttd),
        "mtta": stats(mtta),
        "mttm": stats(mttm),
        "mttr": stats(mttr),
    }

def detect_quality_degradation(
    recent_metrics: dict,
    baseline_metrics: dict,
    thresholds: dict,
) -> list[str]:
    alerts = []
    # Refusal rate spike
    refusal_delta = recent_metrics["refusal_rate"] - baseline_metrics["refusal_rate"]
    if refusal_delta > thresholds.get("refusal_rate_delta", 0.05):
        alerts.append(
            f"Refusal rate increased by {refusal_delta:.1%} above baseline"
        )
    # Output length drop
    length_ratio = recent_metrics["p50_output_length"] / baseline_metrics["p50_output_length"]
    if length_ratio < thresholds.get("output_length_min_ratio", 0.7):
        alerts.append(
            f"P50 output length dropped to {length_ratio:.0%} of baseline"
        )
    return alerts

def audit_alert_routing(
    incidents: list[dict],
    pagerduty_client,
) -> dict:
    routing_issues = []
    for inc in incidents:
        if inc["mtta_minutes"] > inc["mtta_target_minutes"]:
            # Pull the PD escalation log for this incident
            escalation_log = pagerduty_client.get_escalation_log(inc["pagerduty_id"])
            if escalation_log["first_notified_user"] != inc["oncall_engineer"]:
                routing_issues.append({
                    "incident_id": inc["id"],
                    "expected_oncall": inc["oncall_engineer"],
                    "actually_notified": escalation_log["first_notified_user"],
                    "finding": "Alert not routed to on-call engineer",
                })
            elif escalation_log["notification_channel"] == "email":
                routing_issues.append({
                    "incident_id": inc["id"],
                    "finding": "Alert sent via email only; phone not configured",
                })
    return {
        "total_mtta_misses": len([i for i in incidents if i["mtta_minutes"] > i["mtta_target_minutes"]]),
        "routing_issues": routing_issues,
        "routing_issue_rate": len(routing_issues) / len(incidents) if incidents else 0,
    }
